  ('dietitian-moex-06300', 'dietitian', 'dietitian-moex-106-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '對憩室症患者的飲食建議，下列何者較佳？', '["限制纖維飲食", "低油飲食", "高纖維飲食", "避免攝取麩質"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:43+00:00", "source_pdf_sha1": "9cc3bb372ac6", "answer_pdf_sha1": "69c7d5f49224", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06301', 'dietitian', 'dietitian-moex-106-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關急性酒精性肝炎患者的營養治療，下列敘述何者正確？', '["須採取低熱量飲食（25大卡／公斤體重／天）", "若無肝昏迷現象，採用正常蛋白飲食（1～1.2公克／公斤體重／天）", "若有Wernicke’s肝昏迷現象，需補充riboflavin", "應口服補充維生素K"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:43+00:00", "source_pdf_sha1": "9cc3bb372ac6", "answer_pdf_sha1": "69c7d5f49224", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06302', 'dietitian', 'dietitian-moex-106-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關糖尿病照護之敘述，何者錯誤？', '["HbA 可以了解糖尿病人過去二至三個月期間內血糖整體控制狀況 1C", "注射胰島素的病人，均建議以SMBG監測其血糖控制效果", "照護團隊成員有責任教導糖尿病人如何使用SMBG的設備，並正確判讀其數據", "對於每天多次注射胰島素的病人，SMBG建議每天於飯後測量血糖至少3次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:43+00:00", "source_pdf_sha1": "9cc3bb372ac6", "answer_pdf_sha1": "69c7d5f49224", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06303', 'dietitian', 'dietitian-moex-106-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關營養素對糖尿病人血糖的影響，下列敘述何者正確？', '["以糖醇（sugar alcohols）作為甜味劑來源會使血糖上升", "蛋白質攝取可減緩醣類吸收，降低胰島素分泌", "高醣飲食（＞55%總熱量）會增加血三酸甘油酯及飯前血糖", "隨餐適量飲酒，對血糖及胰島素立即之影響極低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:43+00:00", "source_pdf_sha1": "9cc3bb372ac6", "answer_pdf_sha1": "69c7d5f49224", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
